+    #[test]
+    fn select_eviction_at_min_lines_returns_none() {
+        let config = ImportanceRetentionConfig {
+            min_lines: 2,
+            max_lines: 100,
+            ..Default::default()
+        };
+        let lines = VecDeque::from(vec![
+            ScrollbackLine::new("a", 0.1, 0),
+            ScrollbackLine::new("b", 0.1, 0),
